esqlQuery.esql:
// Alert when hourly token consumption exceeds a threshold per model.
// Adjust the token threshold in the final WHERE clause as needed.
FROM metrics-anthropic_metrics.usage-*
| WHERE anthropic.usage.uncached_input_tokens IS NOT NULL AND anthropic.usage.model IS NOT NULL
| STATS total_tokens = SUM(anthropic.usage.uncached_input_tokens) + SUM(anthropic.usage.cached_input_tokens) + SUM(anthropic.usage.cache_creation_input_tokens) + SUM(anthropic.usage.output_tokens) BY anthropic.usage.model
| WHERE total_tokens > 500000
